"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { 
  Plus, MapPin, Users, ArrowLeft, ArrowRight, Loader2
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { supabase } from "@/lib/supabase";

interface Bairro {
  id: string;
  nome: string;
  cidade?: string;
  imagem_url?: string;
}

export default function BairrosPage() {
  const [bairros, setBairros] = useState<Bairro[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchBairros();
  }, []);

  const fetchBairros = async () => {
    try {
      const { data, error } = await supabase
        .from("bairros")
        .select("*")
        .order("created_at", { ascending: false });

      if (error) {
        console.log("Erro ao buscar bairros:", error);
      }
      
      setBairros(data || []);
    } catch (err) {
      console.log("Erro:", err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Loader2 className="h-12 w-12 animate-spin text-blue-600" />
      </div>
    );
  }

  return (
    <main className="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 p-8">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="flex items-center gap-4 mb-8">
          <Link href="/" className="p-2 rounded-lg hover:bg-slate-200 transition-colors">
            <ArrowLeft className="h-5 w-5 text-slate-600" />
          </Link>
          <div>
            <h1 className="text-3xl font-bold text-slate-900">Perfil Gestão</h1>
            <p className="text-slate-500">Gestão de Bairros</p>
          </div>
        </div>

        {/* Botão Novo Bairro */}
        <div className="mb-8">
          <Button className="bg-blue-600 hover:bg-blue-700">
            <Plus className="h-4 w-4 mr-2" />
            Novo Bairro
          </Button>
        </div>

        {/* Lista de Bairros */}
        {bairros.length === 0 ? (
          <div className="text-center py-20">
            <MapPin className="h-16 w-16 text-slate-300 mx-auto mb-4" />
            <h3 className="text-xl font-semibold text-slate-700">Nenhum bairro cadastrado</h3>
            <p className="text-slate-500 mt-2">Clique em "Novo Bairro" para começar</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {bairros.map((bairro) => (
              <Link key={bairro.id} href={`/bairro/${bairro.id}`}>
                <Card className="hover:shadow-lg transition-shadow cursor-pointer overflow-hidden">
                  <div className="h-32 bg-gradient-to-br from-blue-500 to-purple-600 relative">
                    {bairro.imagem_url ? (
                      <img 
                        src={bairro.imagem_url} 
                        alt={bairro.nome}
                        className="w-full h-full object-cover"
                      />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center">
                        <MapPin className="h-12 w-12 text-white/50" />
                      </div>
                    )}
                  </div>
                  <CardContent className="p-4">
                    <h3 className="text-xl font-bold text-slate-900">{bairro.nome}</h3>
                    <p className="text-slate-500 text-sm">{bairro.cidade || "Cidade não informada"}</p>
                    <div className="mt-4 flex items-center text-blue-600 text-sm font-medium">
                      Acessar
                      <ArrowRight className="h-4 w-4 ml-1" />
                    </div>
                  </CardContent>
                </Card>
              </Link>
            ))}
          </div>
        )}
      </div>
    </main>
  );
}
